"""Reusable responsive container renderer for buoyancy and hydrostatic pressure."""
from physics_playground.canvas.player import build_player_document
SCENE=r"""
const scene={draw(ctx,s){const w=s.transform.width,h=s.transform.height,c=s.config.fluidContainer||{},left=w*.22,right=w*.78,top=h*.1,bottom=h*.85;ctx.clearRect(0,0,w,h);ctx.fillStyle='#FAFAFA';ctx.fillRect(0,0,w,h);ctx.fillStyle='rgba(33,150,243,.35)';ctx.fillRect(left,top,right-left,bottom-top);ctx.strokeStyle='#263238';ctx.lineWidth=4;ctx.strokeRect(left,top,right-left,bottom-top);if(c.kind==='buoyancy'){const fraction=c.fraction,objectH=100,waterline=top,cy=waterline+objectH*(fraction-.5)*s.fraction;ctx.fillStyle='#FB8C00';ctx.fillRect(w/2-55,cy-objectH/2,110,objectH);ctx.strokeStyle='#E65100';ctx.strokeRect(w/2-55,cy-objectH/2,110,objectH);ctx.fillStyle='#111';ctx.fillText(`${Math.round(fraction*100)}% submerged`,w/2-48,bottom+30)}else{const y=top+(bottom-top)*(c.depth/c.maxDepth);ctx.strokeStyle='#D32F2F';ctx.lineWidth=4;ctx.beginPath();ctx.moveTo(left,y);ctx.lineTo(right,y);ctx.stroke();ctx.fillStyle='#111';ctx.fillText(`Selected depth ${c.depth.toFixed(1)} m`,left+10,y-10);for(let i=0;i<5;i++){const yy=top+(bottom-top)*i/4;ctx.fillStyle=`rgba(13,71,161,${.18+.16*i})`;ctx.fillRect(left,yy,right-left,(bottom-top)/4)}}}};
"""
def build_fluid_document(*,kind:str,message:str,seed:int,submerged_fraction:float=0.,depth:float=0.,maximum_depth:float=1.)->str:
    config={"durationMs":1500,"autoplay":False,"seed":seed,"tracks":[{"id":"fluid-reveal","label":"Fluid result reveal","x":[0,1]}],"events":[],"completionMessage":message,"fluidContainer":{"kind":kind,"fraction":submerged_fraction,"depth":depth,"maxDepth":maximum_depth},"view":{"minimum":0,"maximum":1}}
    return build_player_document(config=config,scene_javascript=SCENE,logical_width=680,logical_height=500,accessible_label="Fluid container diagram. "+message,idle_hint="Press Play to reveal the fluid result")
